class HashTable:
    def __init__(self, capacity=10):
        self._capacity = capacity
        self._table = [[] for _ in range(self._capacity)]
        self._size = 0

    def _hash(self, key):
        """Hesaplanan hash değerini tablo kapasitesine göre dizin olarak döndürür."""
        return hash(key) % self._capacity

    def insert(self, key, value):
        """Anahtar-değer çiftini hash tablosuna ekler veya anahtar zaten varsa değerini günceller."""
        index = self._hash(key)
        bucket = self._table[index]

        # Anahtarın zaten var olup olmadığını kontrol et, varsa değeri güncelle
        for i, (k, v) in enumerate(bucket):
            if k == key:
                bucket[i] = [key, value]  # Var olan anahtarı güncelle
                return

        # Anahtar bulunamadıysa, yeni bir anahtar-değer çifti ekle
        bucket.append([key, value])
        self._size += 1

    def get(self, key):
        """Anahtarla ilişkili değeri döndürür. Anahtar bulunamazsa KeyError yükseltir."""
        index = self._hash(key)
        bucket = self._table[index]

        for k, v in bucket:
            if k == key:
                return v
        raise KeyError(f"Key '{key}' not found")

    def delete(self, key):
        """Anahtar-değer çiftini hash tablosundan siler. Anahtar bulunamazsa KeyError yükseltir."""
        index = self._hash(key)
        bucket = self._table[index]

        for i, (k, v) in enumerate(bucket):
            if k == key:
                del bucket[i]
                self._size -= 1
                return
        raise KeyError(f"Key '{key}' not found")

    def __len__(self):
        """Hash tablosundaki eleman sayısını döndürür."""
        return self._size

    def __contains__(self, key):
        """Belirtilen anahtarın hash tablosunda olup olmadığını kontrol eder."""
        try:
            self.get(key)
            return True
        except KeyError:
            return False

    def __setitem__(self, key, value):
        """hashtable[key] = value sözdizimine izin verir."""
        self.insert(key, value)

    def __getitem__(self, key):
        """value = hashtable[key] sözdizimine izin verir."""
        return self.get(key)

    def __delitem__(self, key):
        """del hashtable[key] sözdizimine izin verir."""
        self.delete(key)

    def __str__(self):
        """Hash tablosunun okunabilir bir string temsilini döndürür."""
        items = []
        for i, bucket in enumerate(self._table):
            if bucket:
                bucket_str = ", ".join([f"{k}: {v}" for k, v in bucket])
                items.append(f"  Bucket {i}: [{bucket_str}]")
        return "{\n" + "\n".join(items) + "\n}"

    def __repr__(self):
        """Hash tablosunun resmi string temsilini döndürür."""
        return self.__str__()
